  ('aboriginal-6f0ba476-moex-00760', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '政府為了減少一定數量的污染，對兩家污染減量成本不同的廠商收取相同的單位污染排放費，該 政策主要的考量最接近以下何者？', '["淨效益現值", "內部報酬率", "益本比", "成本有效性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00761', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '若一公共支出計畫案可以延續到永遠，第一年開始每年支付100萬成本，從第二年起每年得到120 萬的利益，則下列關於本案的評估之敘述何者正確？', '["淨利益現值為無窮大", "益本比等於1.2", "還本期為第5年", "內部報酬率為5%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00762', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '假設A、B、C三人對公共財（G）的邊際願意支付代價分別為P =20–G、P =15–0.5G、P =30–2G， A B C 每人負擔公共財的邊際成本為5。在兩兩表決的投票方式下，所決定的公共財數量為何？', '["5單位", "12.5單位", "15單位", "20單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00763', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '根據尼斯坎南模型（Niskanenmodel），官僚追求的目標為何？', '["極大化社會福利", "極大化預算規模", "極小化超額負擔", "極大化政府稅收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00764', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '東周的戰國時代有兩名政治家分別提出外交策略，其一是蘇秦所提出的合縱，其二是張儀所提出 的連橫。在現代的公共選擇理論中，合縱與連橫適合用下列那種模型來解釋？', '["操縱議程", "選票互助", "鄧恩斯模型", "雅羅不可能定理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00765', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '下列何者為我國全民健康保險一般保險費收費制度之特色？', '["考量量能原則，按家戶總所得高低收費", "按職業身分採不同計費方式", "所得越高，費率越高", "以家戶為計費單位"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00766', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '下列各項保險之給付項目，何者沒有提供育嬰留職停薪津貼？', '["公教人員保險", "勞工保險", "國民年金保險", "軍人保險"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00767', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '低收入戶得向戶籍所在地直轄市、縣（市）主管機關申請生活扶助，下列敘述何者錯誤？', '["生活扶助以現金給付為主", "因實際需要，得委託適當之社會救助機構、社會福利機構或其他家庭予以收容", "現金給付所定金額，每年調整一次", "直轄市及縣（市）主管機關每年應定期辦理低收入戶、中低收入戶調查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00768', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '假設某一土地每期期末之報酬為$100。每期期末課以地價稅稅額$2，在租稅完全資本化的假設下，', '["該土地稅前收益價格為$1,100", "該土地稅後收益價格 為$1,080", "租稅資本化的數額為$20", "該土地稅後收益價格為$980"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00769', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', 'X財之市場供給為一正斜率直線，市場需求為一水平直線；若對X財從量課稅，則會導致消費者 剩餘（CS）、生產者剩餘（PS）、政府稅收（GR）的變化為：', '["CS減少數等於GR，PS不受影響", "CS減少數大於GR，PS不受影響", "PS減少數等於GR，CS不受影響", "PS減少數大於GR，CS不受影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
